SELECT substation_name 
FROM substation 
ORDER BY substation_name;

SELECT substation_name
FROM substation
WHERE operational_status = 'operational';

SELECT COUNT(*) AS active_user_count
FROM user
WHERE status = 'active';

SELECT COUNT(*) AS active_alert_count
FROM alert
WHERE status = 'active';

SELECT substation_name, location, operational_status
FROM substation
ORDER BY operational_status;

SELECT COUNT(*) AS operational_substations
FROM substation
WHERE operational_status = 'operational';

SELECT substation_name, operational_status
FROM substation
ORDER BY substation_name;

SELECT alert_message
  FROM alert
  WHERE status = 'resolved';
